    dirs = [(1,0), (-1,0), (0,1), (0,-1)]
    for i in range(R):
        for j in range(C):
            if g[i][j] == 6 and not visited[i][j]:
                comp = []
                stack = [(i, j)]
                visited[i][j] = True
                while stack:
                    r, c = stack.pop()
                    comp.append((r, c))
                    for dr, dc in dirs:
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < R and 0 <= nc < C and not visited[nr][nc] and g[nr][nc] == 6:
                            visited[nr][nc] = True
                            stack.append((nr, nc))
                min_r = min(r for r, c in comp)
                max_r = max(r for r, c in comp)
                min_c = min(c for r, c in comp)
                max_c = max(c for r, c in comp)
                # green border
                for r in range(min_r - 1, max_r + 2):
                    for c in range(min_c - 1, max_c + 2):
                        if 0 <= r < R and 0 <= c < C:
                            out[r][c] = 3
                # interior: pink or yellow
                comp_set = set(comp)
                for r in range(min_r, max_r + 1):
                    for c in range(min_c, max_c + 1):
                        if (r, c) in comp_set:
                            out[r][c] = 6
                        else:
                            out[r][c] = 4
    return out

